import { Component, Input, computed, signal } from '@angular/core';

/** Presentational gradient avatar with initials. Deterministic gradient per name
 *  so the same person always looks the same across screens. No network image
 *  dependency — safe for offline preview rendering. */
@Component({
  selector: 'app-avatar',
  standalone: true,
  templateUrl: './avatar.component.html',
  styleUrl: './avatar.component.css',
})
export class AvatarComponent {
  private _name = signal<string>('');
  @Input() set name(value: string) {
    this._name.set(value ?? '');
  }
  @Input() size = 48;
  @Input() ring = false;

  readonly initials = computed(() => {
    const parts = this._name().trim().split(/\s+/).filter(Boolean);
    if (parts.length === 0) return '?';
    if (parts.length === 1) return parts[0].slice(0, 2).toUpperCase();
    return (parts[0][0] + parts[parts.length - 1][0]).toUpperCase();
  });

  readonly gradient = computed(() => {
    const name = this._name();
    let hash = 0;
    for (let i = 0; i < name.length; i++) {
      hash = (hash * 31 + name.charCodeAt(i)) >>> 0;
    }
    const index = (hash % 6) + 1;
    return `var(--grad-${index})`;
  });
}
